def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 8:
            for a in range(8, 3, -1):
                for b in range(1, a + 5):
                    temp = ((ratio - a) ** 7) / (a * b * 0.7 + 1)
                    priority += temp * np.sin(ratio * b / (a + 1)) * np.cos(ratio / (b + 0.5))
            priority += (np.exp(ratio - 7) * np.cos(ratio * 1.3)) ** 2
            for c in range(1, 6):
                priority += np.tanh(priority / (c + 1)) * np.sin(ratio * c * 2.1)
        elif 5 < ratio <= 8:
            for d in range(1, int(np.ceil(ratio)) + 5):
                for e in range(1, d + 4):
                    term = ((ratio - d) ** 4) * np.cos(ratio * e) / (e + 0.3)
                    priority += np.tanh(term) * 1.5
            priority += np.log(ratio + 1) * 12 - np.tanh(ratio - 5) * 3
            if (i + int(item * 2)) % 5 == 0:
                priority *= np.sqrt(bin_cap + 2)
        elif 2 <= ratio <= 5:
            s1, s2 = 0, 0
            for f in range(1, 15):
                s1 += ((ratio - 2) ** f) / (f * 2.1) * np.sin(f * ratio * 0.9)
            for g in range(1, 10):
                s2 += ((5 - ratio) ** g) / (g ** 1.5 + 0.3) * np.cos(g * ratio)
            priority = (s1 * np.cos(5 * ratio) - s2 * np.tanh(3 * ratio)) + np.log(ratio) * 8
            for h in range(1, 4):
                priority += np.sin(h * ratio * i) / (h ** 2 + 1)
            if bin_cap < item * 1.3:
                priority += np.exp(-ratio) * 7
            else:
                priority -= np.log1p(bin_cap) * 3
        elif 1 <= ratio < 2:
            s = 0
            for j in range(1, 20):
                s += ((2 - ratio) ** j) / (j ** 2 + 1) * np.cos(j * ratio * 1.3)
            penalty = 0
            if bin_cap < item * 1.05:
                penalty = np.sqrt(item / (bin_cap + 0.3)) * 5.5
            else:
                penalty = np.cos(25 * ratio) * 3.5
            priority = s + penalty + np.exp(-2 / (ratio + 0.1))
            for k in range(1, 7):
                priority += np.sin(k * ratio * i * 1.1) * ((ratio - 1) ** k) / (k + 0.5)
        elif 0.4 <= ratio < 1:
            s = 0
            for l in range(1, 25):
                s += ((1 - ratio) ** l) / (l ** 1.2 + 0.2)
            priority = s
            if (i + int(item * 2)) % 6 == 0:
                priority *= np.log1p(bin_cap + 5) * 1.7
            else:
                priority /= (np.sqrt(bin_cap + 2.5) + 3)
            for m in range(1, 9):
                priority += ((1 - ratio) ** m) * np.sin(m * item * 1.7) * 0.9
        elif 0.15 <= ratio < 0.4:
            s = 0
            for n in range(1, 20):
                s += ((0.4 - ratio) ** n) / (n * 4.5) * np.cos(n * ratio * 2.5)
            priority = s + 1.2 / (bin_cap + 4)
            if int(item * 1.6) % 5 == 0:
                priority *= 2.8
            else:
                priority /= 3.2
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 4.5
            else:
                priority -= np.exp(-ratio * 1.5) * 3.5
            for o in range(1, 9):
                priority += ((0.4 - ratio) ** o) / (o * 7) * np.cos(item * o * 1.4)
        else:
            s = 0
            for p in range(1, 12):
                s += ((0.15 - ratio) ** p) / (p * 5.2) * np.sin(p * item * 1.1)
            priority = s + 3 / (bin_cap + 5)
            if int(item * 0.8) % 6 == 0:
                priority *= 3.5
            else:
                priority /= 3.5
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 5.5
            else:
                priority -= np.exp(-ratio * 2.5) * 4.5
            for q in range(1, 10):
                priority += ((0.15 - ratio) ** q) / (q * 8) * np.cos(item * q * 0.9)
        if bin_cap < item * 0.7:
            priority += np.log1p(item ** 2 * bin_cap) * 6
            for r in range(1, 4):
                priority += np.sin(r * ratio * i * 1.2) * 0.8
        elif bin_cap > item * 3.0:
            priority -= np.exp(-4 * ratio) * 5.5
            for s in range(1, 5):
                priority -= np.cos(s * ratio * (i + 2)) * 0.5
        for t in range(1, 5):
            if (i + t) % 4 == 0:
                priority += np.sin(ratio * (i + t) * 1.1) * 0.4
            else:
                priority -= np.cos(ratio * (i + t) * 1.3) * 0.4
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.4) * 0.8
            for u in range(1, 3):
                priority += np.tanh(priority / (u + 1)) * np.sin(u * ratio)
        else:
            priority -= np.cos(ratio * i * 1.4) * 0.8
            for v in range(1, 3):
                priority -= np.tanh(priority / (v + 2)) * np.cos(v * ratio)
        priorities[i] = priority
    return priorities
